function _implementation() internal view override returns (address) {
    address implementation = ERC1967Utils.getImplementation();
    try IBeacon(implementation).implementation() returns (address result) {
        return result;
    } catch {
        return implementation;
    }
}

function _rawSignatureValidation(
    bytes32 hash,
    bytes calldata signature
) internal view virtual override returns (bool) {
    (address recovered, ECDSA.RecoverError err, ) = ECDSA.tryRecoverCalldata(hash, signature);
    return signer() == recovered && err == ECDSA.RecoverError.NoError;
}

function getUpgradeInterfaceVersion(address addr) internal view returns (string memory) {
    // Use staticcall to prevent forge from broadcasting it, and to ensure no state changes
    (bool success, bytes memory returndata) = addr.staticcall(
        abi.encodeWithSignature("UPGRADE_INTERFACE_VERSION()")
    );
    if (success && returndata.length > 32) {
        return abi.decode(returndata, (string));
    } else {
        return "";
    }
}

function royaltyInfo(
    uint256 tokenId,
    uint256 salePrice
) external view virtual override returns (address receiver, uint256 royaltyAmount) {
    (address recipient, uint256 bps) = getRoyaltyInfoForToken(tokenId);
    receiver = recipient;
    royaltyAmount = (salePrice * bps) / 10_000;
}

function _setApproveTransferExtension(address extension, bool enabled) internal override {
    if (ERC165Checker.supportsInterface(extension, type(IERC721CreatorExtensionApproveTransfer).interfaceId)) {
        _extensionApproveTransfers[extension] = enabled;
        emit ExtensionApproveTransferUpdated(extension, enabled);
    }
}

function tokenExtension(uint256 tokenId) public view virtual override returns (address extension) {
    require(_exists(tokenId), "Nonexistent token");
    extension = _tokenExtension(tokenId);
    require(extension != address(0), "No extension for token");
    require(!_blacklistedExtensions.contains(extension), "Extension blacklisted");
}

function burn(uint256 tokenId) public virtual override nonReentrant {
    require(_isApprovedOrOwner(msg.sender, tokenId), "Caller is not owner or approved");
    address owner = ownerOf(tokenId);
    address extension = _tokenExtension(tokenId);
    _burn(tokenId);
    _postBurn(owner, tokenId, extension);
}

function execute(
    address account,
    bytes32 salt,
    bytes32 mode,
    bytes calldata data
) public virtual returns (bytes[] memory returnData) {
    bytes calldata executionCalldata = _validateExecution(account, salt, mode, data);
    returnData = _execute(account, mode, salt, executionCalldata); // Prioritize errors thrown in _execute
    return returnData;
}

function _validateReachableThreshold(address account) internal view virtual {
    uint256 totalSigners = getSignerCount(account);
    uint64 currentThreshold = threshold(account);
    require(
        totalSigners >= currentThreshold,
        ERC7579MultisigUnreachableThreshold(
            uint64(totalSigners), // Safe cast. Economically impossible to overflow.
            currentThreshold
        )
    );
}

function deployUUPSProxy(
    string memory contractName,
    bytes memory initializerData,
    Options memory opts
) internal returns (address) {
    address impl = deployImplementation(contractName, opts);

    return Core.deploy("ERC1967Proxy.sol:ERC1967Proxy", abi.encode(impl, initializerData), opts);
}

function deployBeacon(
    string memory contractName,
    address initialOwner,
    Options memory opts
) internal returns (address) {
    address impl = deployImplementation(contractName, opts);

    return Core.deploy("UpgradeableBeacon.sol:UpgradeableBeacon", abi.encode(impl, initialOwner), opts);
}

function take(Currency currency, IPoolManager poolManager, address recipient, uint256 amount, bool claims)
        internal
    {
        // Early return when amount is 0 given that some tokens may revert in this case
        if (amount == 0) return;

        claims ? poolManager.mint(recipient, currency.toId(), amount) : poolManager.take(currency, recipient, amount);
    }

function emergencyExecute(
    address targetAddress,
    bytes calldata targetCallData
) external onlyPartyDao onlyIfEmergencyActionsAllowed {
    (bool success, bytes memory res) = targetAddress.delegatecall(targetCallData);
    if (!success) {
        res.rawRevert();
    }
    emit EmergencyExecute(targetAddress, targetCallData);
}

function setSigningThresholdBps(uint96 thresholdBps) external {
    if (thresholdBps > 10_000) {
        revert InvalidBps();
    }

    Party party = Party(payable(msg.sender));
    emit SigningThresholdBpsSet(party, signingThresholdBps[party], thresholdBps);
    signingThresholdBps[party] = thresholdBps;
}

function subscriptionOf(address registrant) external view returns (address subscription) {
    subscription = _registrations[registrant];
    if (subscription == address(0)) {
        revert NotRegistered(registrant);
    } else if (subscription == registrant) {
        subscription = address(0);
    }
}

function updateOperatorFilterRegistryAddress(address newRegistry) public virtual {
    if (msg.sender != owner()) {
        revert OnlyOwner();
    }
    operatorFilterRegistry = IOperatorFilterRegistry(newRegistry);
    emit OperatorFilterRegistryAddressUpdated(newRegistry);
}

function revokeOperatorFilterRegistry() public {
    if (msg.sender != owner()) {
        revert OnlyOwner();
    }
    // if registry has been revoked, do not allow further updates
    if (isOperatorFilterRegistryRevoked) {
        revert RegistryHasBeenRevoked();
    }

    // set to zero address to bypass checks
    operatorFilterRegistry = IOperatorFilterRegistry(address(0));
    isOperatorFilterRegistryRevoked = true;
    emit OperatorFilterRegistryRevoked();
}

function updateOperatorFilterRegistryAddress(address newRegistry) public override {
    if (msg.sender != owner()) {
        revert OnlyOwner();
    }
    // if registry has been revoked, do not allow further updates
    if (isOperatorFilterRegistryRevoked) {
        revert RegistryHasBeenRevoked();
    }

    operatorFilterRegistry = IOperatorFilterRegistry(newRegistry);
    emit OperatorFilterRegistryAddressUpdated(newRegistry);
}

function safeBatchTransferFrom(
    address from,
    address to,
    uint256[] memory ids,
    uint256[] memory amounts,
    bytes memory data
) public virtual override onlyAllowedOperator(from) {
    super.safeBatchTransferFrom(from, to, ids, amounts, data);
}

function _mintRewards(address _staker, uint256 _rewards) internal virtual override {
    require(_rewards <= rewardTokenBalance, "Not enough reward tokens");
    rewardTokenBalance -= _rewards;
    CurrencyTransferLib.transferCurrencyWithWrapper(
        rewardToken,
        address(this),
        _staker,
        _rewards,
        nativeTokenWrapper
    );
}

function setAccountDataEncryptionKey(bytes memory dataEncryptionKey) public {
  require(dataEncryptionKey.length >= 33, "data encryption key length <= 32");
  Account storage account = accounts[msg.sender];
  account.dataEncryptionKey = dataEncryptionKey;
  emit AccountDataEncryptionKeySet(msg.sender, dataEncryptionKey);
}

function _setCloseFactor(
    uint newCloseFactorMantissa
) external returns (uint) {
    // Check caller is admin
    require(msg.sender == admin, "only admin can set close factor");

    uint oldCloseFactorMantissa = closeFactorMantissa;
    closeFactorMantissa = newCloseFactorMantissa;
    emit NewCloseFactor(oldCloseFactorMantissa, closeFactorMantissa);

    return uint(Error.NO_ERROR);
}

function _upgradeToAndCall(
    address newImplementation,
    bytes memory data,
    bool forceCall
) internal {
    _upgradeTo(newImplementation);
    if (data.length > 0 || forceCall) {
        functionDelegateCall(newImplementation, data);
    }
}

function functionDelegateCall(
    address target,
    bytes memory data,
    string memory errorMessage
) internal returns (bytes memory) {
    (bool success, bytes memory returndata) = target.delegatecall(data);
    return verifyCallResult(success, returndata, errorMessage);
}

function authorizeValidatorSigner(
  address signer,
  uint8 v,
  bytes32 r,
  bytes32 s
) external nonReentrant {
  legacyAuthorizeSignerWithSignature(signer, ValidatorSigner, v, r, s);
  setIndexedSigner(signer, ValidatorSigner);

  require(!getValidators().isValidator(msg.sender), "Cannot authorize validator signer");
  emit ValidatorSignerAuthorized(msg.sender, signer);
}

function authorizeValidatorSignerWithPublicKey(
  address signer,
  uint8 v,
  bytes32 r,
  bytes32 s,
  bytes calldata ecdsaPublicKey
) external nonReentrant {
  legacyAuthorizeSignerWithSignature(signer, ValidatorSigner, v, r, s);
  setIndexedSigner(signer, ValidatorSigner);

  require(
    getValidators().updateEcdsaPublicKey(msg.sender, signer, ecdsaPublicKey),
    "Failed to update ECDSA public key"
  );
  emit ValidatorSignerAuthorized(msg.sender, signer);
}

function signerToAccount(address signer) external view returns (address) {
  address authorizingAccount = authorizedBy[signer];
  if (authorizingAccount != address(0)) {
    return authorizingAccount;
  } else {
    require(isAccount(signer), "Must first register address with Account.createAccount");
    return signer;
  }
}

function createAccount() public returns (bool) {
  require(
    isNotAccount(msg.sender) && isNotAuthorizedSigner(msg.sender),
    "Account already exists or address is an authorized signer for another account"
  );
  Account storage account = accounts[msg.sender];
  account.exists = true;
  emit AccountCreated(msg.sender);
  return true;
}

function authorizeAttestationSigner(address signer, uint8 v, bytes32 r, bytes32 s) public {
  legacyAuthorizeSignerWithSignature(signer, AttestationSigner, v, r, s);
  setIndexedSigner(signer, AttestationSigner);

  emit AttestationSignerAuthorized(msg.sender, signer);
}

function authorizeSigner(address signer, bytes32 role) public {
  require(isAccount(msg.sender), "Must first register sender with Account.createAccount");
  require(
    isNotAccount(signer) && isNotAuthorizedSignerForAnotherAccount(msg.sender, signer),
    "Cannot re-authorize address signer"
  );

  signerAuthorizations[msg.sender][role][signer] = SignerAuthorization({
    started: true,
    completed: false
  });
  emit SignerAuthorizationStarted(msg.sender, signer, role);
}
